const { spawn } = require('child_process');
const path = require('path');

const allowedEffects = ['grayscale', 'sepia', 'blur', 'enhance'];
const allowedFormats = ['jpg', 'jpeg', 'png', 'gif'];
const dimensionRegex = /^\d+x\d+$/;

function validateFileName(fileName) {
  const ext = path.extname(fileName).toLowerCase().slice(1);
  return allowedFormats.includes(ext);
}

function validateDimensions(dimensions) {
  return dimensionRegex.test(dimensions);
}

function validateEffects(effects) {
  return effects.every(effect => allowedEffects.includes(effect));
}

function resizeImage(inputFile, outputFile, dimensions, effects) {
  if (!validateFileName(inputFile) || !validateFileName(outputFile)) {
    throw new Error('Invalid file format.');
  }
  if (!validateDimensions(dimensions)) {
    throw new Error('Invalid dimensions format.');
  }
  if (!validateEffects(effects)) {
    throw new Error('Invalid effects.');
  }

  const args = [inputFile, '-resize', dimensions];

  effects.forEach(effect => {
    switch (effect) {
      case 'grayscale':
        args.push('-colorspace', 'Gray');
        break;
      case 'sepia':
        args.push('-sepia-tone', '80%');
        break;
      case 'blur':
        args.push('-blur', '0x8');
        break;
      case 'enhance':
        args.push('-enhance');
        break;
    }
  });

  args.push(outputFile);

  const convert = spawn('convert', args);

  convert.on('error', (err) => {
    console.error('Error:', err);
  });

  convert.on('close', (code) => {
    if (code !== 0) {
      console.error(`convert process exited with code ${code}`);
    } else {
      console.log('Image processing complete.');
    }
  });
}

